<template>
    <div class="my-popups">
        <loader :is-visible="isLoading"></loader>
        <div class="modal d-block">
            <div class="modal-dialog modal-dialog-centered">
                <div class="modal-content">
                    <div class="modal-header theme-primary partition-full d-flex">
                        <h4 class="modal-title">{{ $t('InsertLineItems') }}</h4>
                        <button type="button" class="close" v-on:click="Close">
                            <em class="fa fa-times" aria-hidden="true"></em>
                        </button>
                    </div>

                    <div class="modal-body">
                        <dynamic-form lang="en" ref="dynamicform" :buttons="buttons" :schema="FormSchema"
                            v-on:OnSubmit="onSubmit"></dynamic-form>
                    </div>
                </div>
            </div>
        </div>
    </div>
</template>
<script>
import { locateBillingService } from "../../../services/locateBillingService";
export default {
    props: {
        ColumnIds: {
            type: String,
            required: true
        },
        reqFrom:{
            type: String,
            required: true
        }
    },
    data() {
        return {
            isLoading: false,
            FormSchema: [
                {
                    layoutType: "double",
                    Data: [
                        {
                            astype: "SelectField",
                            label: this.$t('WorkCode'),
                            name: "WorkCode",
                            value: "",
                            config: {
                                options: []
                            },
                            placeholder: this.$t('SelectWorkCode'),
                            validationRules: { "required": true, max: 100 },
                        },
                        {
                            astype: "NumericField",
                            label: this.$t('ItemCount'),
                            name: "ItemCount",
                            value: "0",
                            validationRules: { "required": true, max: 100 },
                        },
                    ],
                }
            ],
            buttons: [
                {
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-save pr-2'></i>Save",
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Close",
                    onClick: this.Close
                }
            ],
        }
    },
    created: async function () {
        var vm = this;
        await vm.GetWorkCodeData();
    },
    methods: {
        GetWorkCodeData: async function () {
            var vm = this;
            locateBillingService.GetWorkCodeData().then(response => {
                if (response.data) {
                    var options = response.data;
                    vm.$refs.dynamicform.updateProperty("WorkCode", "config.options", options);
                    vm.$refs.dynamicform.UpdateKeyValue();
                }
            });
        },
        Close: function () {
            this.$parent.IsCloneLineItem = false;
        },
        onSubmit(formfields, val) {
            var vm = this;
            formfields.ItemCount=="0" ? vm.$refs.dynamicform.updateProperty("ItemCount", "value", "") : formfields.ItemCount;
            var CountValue= vm.$refs.dynamicform.getPropertyValue("ItemCount", "value");
            var jsonobj = {
                WorkCodeId: formfields.WorkCode,
                Count: formfields.ItemCount,
                LineIds: vm.ColumnIds,
                ReqFrom: vm.reqFrom
            };
            if(CountValue){
            locateBillingService.BulkInsertWorkCode(jsonobj).then((response) => {
                if (response.data.msg == 'Success') {
                        vm.ShowAlert(vm.$t('UpdatedSuccess', [vm.$t('LineItem')]), "Success", true, vm.$t('Alert'));
                        vm.Close();
                        vm.$parent.loadLineItems();
                        vm.$parent.refreshKey += 1;
                }
                else {
                    vm.ShowAlert(vm.$t("AddedError", [vm.$t("Tag")]), "failure", true, vm.$t("Alert"));
                    vm.Close();
                }
            });
        }
        }
    }
}
</script>